    });
    await waitFor(() => {
      expect(screen.queryByTestId('dialog-content')).toBeNull();
    });
    expect(document.body.style.pointerEvents).toBe('');
    expect(useOverlayStackApi().getState().overlays).toHaveLength(0);
  });
